from pathlib import Path
import ast

OUT = []

def add(s=''):
    OUT.append(str(s))

def show(fname, ranges=None, terms=None):
    p = Path(fname)
    add(f'===== {fname} exists={p.exists()} size={p.stat().st_size if p.exists() else None} =====')
    if not p.exists():
        return
    txt = p.read_text(errors='replace')
    lines = txt.splitlines()
    try:
        tree = ast.parse(txt)
        for node in ast.walk(tree):
            if isinstance(node, (ast.ClassDef, ast.FunctionDef, ast.AsyncFunctionDef)):
                add(f'AST {type(node).__name__} {node.name} {node.lineno}-{getattr(node, "end_lineno", node.lineno)}')
    except Exception as e:
        add(f'AST_FAIL {e!r}')
    printed = set()
    if ranges:
        for a,b in ranges:
            a=max(1,a); b=min(len(lines),b)
            printed.add((a,b))
            add(f'--- lines {a}-{b} ---')
            for j in range(a-1,b):
                s=lines[j]
                if len(s)>160: s=s[:160]+'...'
                add(f'{j+1:04d}: {s}')
    if terms:
        for term in terms:
            idx = next((i for i,l in enumerate(lines) if term in l), None)
            add(f'--- term {term!r} line={None if idx is None else idx+1} ---')
            if idx is not None:
                a=max(1,idx-12); b=min(len(lines),idx+45)
                key=(a,b)
                if key in printed:
                    continue
                printed.add(key)
                for j in range(a-1,b):
                    s=lines[j]
                    if len(s)>160: s=s[:160]+'...'
                    add(f'{j+1:04d}: {s}')
    add('')

show('model.py', ranges=[(1,35),(80,180),(180,260)], terms=['class Pi0VLABenchAgent','def _infer_actions','def predict','return pos'])
show('predict.py', ranges=[(1,110)], terms=['Evaluator','evaluate_single_episode','def run_with_evaluator','def main'])
Path('current_inspection.txt').write_text('\n'.join(OUT))
print('\n'.join(OUT[:420]))
